fn inRanges(ranges: []const Range, cp: u32) bool {
    // Binary search: largest range with lo <= cp, then bounds check.
    var lo: usize = 0;
    var hi: usize = ranges.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        if (ranges[mid].lo <= cp) lo = mid + 1 else hi = mid;
    }
    if (lo == 0) return false;
    return cp < ranges[lo - 1].hi;
}

/// Unicode \p{L} (any letter category).
pub fn isLetter(cp: u32) bool {
    if (cp < 0x80) return (cp >= 'a' and cp <= 'z') or (cp >= 'A' and cp <= 'Z');
    return inRanges(&letter_ranges, cp);
}

/// Unicode \p{N} (any number category).
pub fn isNumber(cp: u32) bool {
    if (cp < 0x80) return cp >= '0' and cp <= '9';
    return inRanges(&number_ranges, cp);
}

/// llama.cpp's \s whitespace set (unicode_set_whitespace).
pub fn isWhitespace(cp: u32) bool {
    return switch (cp) {
        0x0009, 0x000A, 0x000B, 0x000C, 0x000D, 0x0020, 0x0085, 0x00A0, 0x1680, 0x2000, 0x2001, 0x2002, 0x2003, 0x2004, 0x2005, 0x2006, 0x2007, 0x2008, 0x2009, 0x200A, 0x2028, 0x2029, 0x202F, 0x205F, 0x3000 => true,
        else => false,
    };
}

test {
    _ = @import("unicode_categories_tests.zig");
}

test "ascii fast paths agree with the range tables" {
    var cp: u32 = 0;
    while (cp < 0x80) : (cp += 1) {
        try std.testing.expectEqual(inRanges(&letter_ranges, cp), isLetter(cp));
        try std.testing.expectEqual(inRanges(&number_ranges, cp), isNumber(cp));
    }
}
